// ── Stationid remapping ──────────────────────────────────────────
// Country prefix logic:
//   US kiosks  → USB####
//   CA kiosks  → CAB####
//   FR kiosks  → FRB####
// Counters restart at 0001 per country.
const ID_MAP = {
    'CS0001': 'USB0001',
    'CS0002': 'CAB0001',
    'CS0003': 'CAB0002',
    'CS0004': 'CAB0003',
    'CS0005': 'CAB0004',
    'CS0006': 'CAB0005',
    'CS0007': 'CAB0006',
    'CS0008': 'CAB0007',
    'CS0009': 'CAB0008',
    'CS0010': 'CAB0009',
    'CS0011': 'CAB0010'
};

const kiosks = global.get('stations') || [];
if (kiosks.length === 0) {
    node.warn('global.stations is empty — nothing to migrate');
    return null;
}

const baseTs = Math.floor(Date.now() / 1000);

msg.payload = kiosks.map((kiosk, index) => {
    const newId = ID_MAP[kiosk.stationid] || kiosk.stationid;
    const provisionid = 'id-' + String(baseTs + index).padStart(10, '0');
    const modulesRaw = Array.isArray(kiosk.modules) ? kiosk.modules : Object.values(kiosk.modules || {});
    const mod0  = modulesRaw[0];

    // ── info block: normalise field names to match old kiosk schema ──
    const info = {
        location:       kiosk.info.location       || '',
        place:          kiosk.info.place           || '',
        locationtype:   kiosk.info.locationtype    || '',
        stationaddress: kiosk.info.stationaddress  || kiosk.info.address || '',
        city:           kiosk.info.city            || '',
        state:          kiosk.info.state           || '',
        zip:            kiosk.info.zip             || '',
        country:        kiosk.info.country         || '',
        lat:            kiosk.info.lat             || null,
        lon:            kiosk.info.lon             || null,
        client:         kiosk.info.clientId        || kiosk.info.client  || '',
        clientId:       kiosk.info.clientId        || kiosk.info.client  || '',
        group:          kiosk.info.group           || '',
        rep:            kiosk.info.rep             || '',
        account:        kiosk.info.account         || '',
        accountpercent: kiosk.info.accountpercent  || 0,
        reppercent:     kiosk.info.reppercent      || 0
    };

    const modules = modulesRaw.map(mod => ({
        ...mod,
        lastUpdated: mod.lastUpdated || new Date().toISOString()
    }));

    const timestamp = mod0
        ? (mod0.lastUpdated || new Date().toISOString())
        : new Date().toISOString();

    return {
        stationid:   newId,
        provisionid,
        hardware:    kiosk.hardware  || {},
        pricing:     kiosk.pricing   || {},
        ui:          kiosk.ui        || {},
        info,
        modules,
        total:       kiosk.total    || 0,
        full:        kiosk.full     || 0,
        slot:        kiosk.slot     || 0,
        empty:       kiosk.empty    || 0,
        charging:    kiosk.charging || 0,
        active:      kiosk.active   !== false,
        enabled:     kiosk.enabled  !== false,
        vendslot:    kiosk.vendslot || '',
        timestamp
    };
});

node.status({ fill: 'blue', shape: 'dot', text: msg.payload.length + ' kiosks queued' });
return msg;

const kiosk = msg.payload || {};
const modules = Array.isArray(kiosk.modules) ? kiosk.modules : [];
const configuredPower = Number(kiosk.hardware?.power);
const fullThreshold = Number.isFinite(configuredPower) ? configuredPower : 80;

let count = 0;
let slotscount = 0;
let lockcount = 0;

modules.forEach(mod => {
    const slots = Array.isArray(mod.slots) ? mod.slots : [];
    slotscount += slots.length;
    slots.forEach(slot => {
        if (slot?.lock) lockcount++;
        if (
            slot &&
            slot.status === 1 &&
            slot.sn &&
            slot.sn !== 0 &&
            typeof slot.batteryLevel === 'number' &&
            slot.batteryLevel >= fullThreshold &&
            !slot.lock
        ) {
            count++;
        }
    });
});

kiosk.count = count;
kiosk.slotscount = slotscount;
kiosk.lockcount = lockcount;
kiosk.zerocount = kiosk.zerocount || 0;
kiosk.lastUpdate = kiosk.timestamp;
kiosk.chargers = count === 0 ? 'soldout' : count;

msg.payload = kiosk;
return msg;

const kiosk = msg.payload;

msg.stationid = kiosk.stationid;
msg.provisionid = kiosk.provisionid;
msg.payload = {
    path: 'kiosks/' + kiosk.provisionid,
    content: kiosk
};

node.status({ fill: 'yellow', shape: 'ring', text: 'Writing ' + kiosk.provisionid });
return msg;

const stationid  = msg.stationid  || '?';
const provisionid = msg.provisionid || '?';

if (msg.error) {
    node.status({ fill: 'red', shape: 'ring', text: 'Error: ' + provisionid });
    node.error('Firestore write failed: ' + JSON.stringify(msg.error), msg);
    msg.payload = { ok: false, provisionid, stationid, error: msg.error };
} else {
    node.status({ fill: 'green', shape: 'dot', text: '✓ ' + provisionid });
    msg.payload = { ok: true, provisionid, stationid };
}
return msg;
